	name: 'about',
	components: { uniList, uniListItem, uniNoticeBar },
	computed: mapState(['allSelect']),
	methods: {
		setAllSelect() {
			this.$store.commit('SET_ALLSELECT', !this.allSelect);
		}
	}
};
